/**
 * MedX checkbox runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Handles tri-state checkboxes for bulk inventory selection and compliance toggles.
 */
const CHECKBOX_STATES = Object.freeze({
  unchecked: { checked: false, indeterminate: false },
  checked: { checked: true, indeterminate: false },
  indeterminate: { checked: false, indeterminate: true },
});

const checkboxGroups = new Map();

function deriveNextState(current) {
  if (current.indeterminate || !current.checked) return CHECKBOX_STATES.checked;
  return CHECKBOX_STATES.unchecked;
}

function createCheckboxGroup(groupId, items) {
  const checkboxes = items.map((item, index) => ({
    id: `${groupId}-item-${index}`,
    label: item.label,
    value: item.value,
    disabled: Boolean(item.disabled),
    ...CHECKBOX_STATES.unchecked,
    metadata: item.metadata ?? {},
  }));

  const group = {
    id: groupId,
    checkboxes,
    selectAllEnabled: true,
    onChange: null,
  };
  checkboxGroups.set(groupId, group);
  return group;
}

function toggleCheckbox(groupId, checkboxId) {
  const group = checkboxGroups.get(groupId);
  if (!group) return null;
  const cb = group.checkboxes.find((c) => c.id === checkboxId);
  if (!cb || cb.disabled) return null;
  const next = deriveNextState(cb);
  Object.assign(cb, next);
  syncGroupIndeterminate(group);
  if (group.onChange) group.onChange(getGroupSelection(groupId));
  return { ...cb };
}

function toggleSelectAll(groupId) {
  const group = checkboxGroups.get(groupId);
  if (!group || !group.selectAllEnabled) return null;
  const enabled = group.checkboxes.filter((c) => !c.disabled);
  const allChecked = enabled.every((c) => c.checked);
  const target = allChecked ? CHECKBOX_STATES.unchecked : CHECKBOX_STATES.checked;
  for (const cb of enabled) Object.assign(cb, target);
  syncGroupIndeterminate(group);
  return getGroupSelection(groupId);
}

function syncGroupIndeterminate(group) {
  const enabled = group.checkboxes.filter((c) => !c.disabled);
  const checkedCount = enabled.filter((c) => c.checked).length;
  if (checkedCount === 0) return;
  if (checkedCount === enabled.length) return;
  for (const cb of enabled) {
    if (!cb.checked) Object.assign(cb, CHECKBOX_STATES.indeterminate);
  }
}

function getGroupSelection(groupId) {
  const group = checkboxGroups.get(groupId);
  if (!group) return null;
  const selected = group.checkboxes.filter((c) => c.checked).map((c) => c.value);
  const enabled = group.checkboxes.filter((c) => !c.disabled);
  return {
    groupId,
    selected,
    selectedCount: selected.length,
    totalCount: group.checkboxes.length,
    allSelected: selected.length === enabled.length && enabled.length > 0,
    someSelected: selected.length > 0 && selected.length < enabled.length,
  };
}

async function runMedxCheckbox() {
  console.log("[medx:ui:checkbox] runtime initialized");

  const inventoryGroup = createCheckboxGroup("inventory-bulk", [
    { label: "SKU-1042 — Influenza Vaccine", value: "SKU-1042", metadata: { qty: 1200 } },
    { label: "SKU-2088 — Surgical Masks (box)", value: "SKU-2088", metadata: { qty: 5000 } },
    { label: "SKU-3011 — Insulin Pens", value: "SKU-3011", metadata: { qty: 340, coldChain: true } },
    { label: "SKU-4490 — IV Saline Bags", value: "SKU-4490", metadata: { qty: 800 } },
    { label: "SKU-5502 — Expired Lot (locked)", value: "SKU-5502", disabled: true },
  ]);

  toggleCheckbox("inventory-bulk", "inventory-bulk-item-0");
  toggleCheckbox("inventory-bulk", "inventory-bulk-item-2");
  toggleSelectAll("inventory-bulk");
  const afterSelectAll = getGroupSelection("inventory-bulk");
  toggleCheckbox("inventory-bulk", "inventory-bulk-item-1");
  const partial = getGroupSelection("inventory-bulk");

  console.log(`[medx:ui:checkbox] groups=${checkboxGroups.size}`);
  console.log("[medx:ui:checkbox] selectAll", afterSelectAll?.selectedCount);
  console.log("[medx:ui:checkbox] partial", partial?.someSelected);
  console.log("[medx:ui:checkbox] bootstrap complete");
}

module.exports = runMedxCheckbox;
